import type { UserManagerSettings } from 'oidc-client-ts';

export interface ConfigOptions {
  configOptions: (issuer: string, clientId: string, redirectUri: string) => UserManagerSettings;
}

class OidcConfigService implements ConfigOptions {
  configOptions(issuer: string, clientId: string, redirectUri: string): UserManagerSettings {
    const url = new URL(window.location.href);
    const baseUri = url.host;
    const proto = url.protocol;
    const postLogoutRedirectUri = `${proto}//${baseUri}`;
    
    
    
    return {
      authority: issuer,
      client_id: clientId,
      redirect_uri: redirectUri,
      response_type: 'code',
      scope: 'openid profile email',
      automaticSilentRenew: true,
      silent_redirect_uri: redirectUri,
      post_logout_redirect_uri: postLogoutRedirectUri,
      monitorSession: true,
      // oidc-client-ts automatically stores user data in sessionStorage
      // with key pattern: oidc.user:{authority}:{client_id}
    };
  }
}

export const oidcConfigService = new OidcConfigService();

