import { Route } from 'react-router-dom';
import { OAuthCallback } from './components/OAuthCallback';
import { UserProfile } from './components/UserProfile';

/**
 * AuthRoutes - Array of Route elements for auth-related routes
 * These should be spread into the app's Routes component
 * 
 * Usage:
 * <Routes>
 *   <Route path="/" element={<Home />} />
 *   {...AuthRoutes}
 * </Routes>
 */
export const AuthRoutes = [
  <Route key="oauth-callback" path="/lib-auth-oauth-callback" element={<OAuthCallback />} />,
  <Route key="user-profile" path="/lib-user-profile" element={<UserProfile />} />,
];

