import axios, { type AxiosError, type InternalAxiosRequestConfig } from 'axios';
import { configService } from './config.service';

// Store login function to avoid circular dependency
let loginFunction: ((issuer: string, clientId: string, redirectUri: string) => Promise<void>) | null = null;

export const setLoginFunctions = (
  loginFn: (issuer: string, clientId: string, redirectUri: string) => Promise<void>
) => {
  loginFunction = loginFn;
};

// Store UserManager reference for interceptor access
let globalUserManager: any = null;

export const setGlobalUserManager = (manager: any) => {
  globalUserManager = manager;
};

export const getGlobalUserManager = () => globalUserManager;

// Track if interceptor is already set up to avoid duplicates
let interceptorSetup = false;

export const setupAuthInterceptor = () => {
  // Prevent multiple interceptor registrations
  if (interceptorSetup) {
    return;
  }
  interceptorSetup = true;

  // Request interceptor
  axios.interceptors.request.use(
    async (config: InternalAxiosRequestConfig) => {
  
      if (config.headers && (config.headers['X-Skip-Intercept'] || config.headers['x-skip-intercept'])) {
        const newConfig = { ...config };
        if (newConfig.headers) {
          delete newConfig.headers['X-Skip-Intercept'];
          delete newConfig.headers['x-skip-intercept'];
        }
        return newConfig;
      }

      const headers = config.headers || {};
      const existingAuthHeader = (headers as any)['Authorization'] || (headers as any)['authorization'];
      
      if (!existingAuthHeader) {
        let accessToken: string | null = null;
        if (globalUserManager) {
          try {
            const user = await globalUserManager.getUser();
            if (user && user.access_token) {
              accessToken = user.access_token;
              // Update sessionStorage with fresh token
              if (accessToken) {
                sessionStorage.setItem('access_token', accessToken);
              }
            }
          } catch (error) {
            console.warn('[Auth Interceptor] Failed to get user from UserManager:', error);
         
          }
        }
        
        if (!accessToken) {
          accessToken = sessionStorage.getItem('access_token');
        }
        
        if (accessToken) {
          // Set Authorization header (matching Angular exactly)
          // Ensure headers object exists
          if (!config.headers) {
            config.headers = {} as any;
          }
          
          // Set Authorization header - try multiple methods to ensure it works
          const authHeader = `Bearer ${accessToken}`;
          
          // Method 1: Direct property assignment (standard Axios)
          (config.headers as any)['Authorization'] = authHeader;
          
          // Method 2: Also set as common header (Axios uses common headers for all requests)
          if (!config.headers.common) {
            (config.headers as any).common = {} as any;
          }
          (config.headers as any).common['Authorization'] = authHeader;
         
        }
      }
      return config;
    },
    (error) => Promise.reject(error)
  );

  // Response interceptor
  axios.interceptors.response.use(
    (response) => response,
    async (error: AxiosError) => {
      if (error.response?.status === 401) {
        const authenticateHeader = error.response.headers['www-authenticate'] as string | undefined;
        const as_uri = authenticateHeader?.match(/as_uri="([^"]+)"/);
        const realm = authenticateHeader?.match(/realm="([^"]+)"/);
        const realms = realm ? realm[1] : ' ';
        const issuer = as_uri ? as_uri[1] + '/realms/' + realms : configService.default_issuer;

        const url = new URL(window.location.href);
        const baseUri = url.host;
        const proto = url.protocol;
        const redirectUri = `${proto}//${baseUri}/lib-auth-oauth-callback`;

        if (loginFunction) {
          loginFunction(issuer, configService.clientId, redirectUri).catch(() => {});
        }
      } else if (error.response?.status === 400 && error.message === 'Session not active') {
        sessionStorage.clear();
      } else {
        return Promise.reject(error);
      }

      const message = error.response?.status === 401 ? error.message : '';
      return Promise.reject(new Error(message));
    }
  );
};


