import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

interface UserDropdownProps {
  firstName: string;
  lastName: string;
  email: string;
}

export const UserDropdown = ({ firstName, lastName, email }: UserDropdownProps) => {
  const { logout } = useAuth();
  const navigate = useNavigate();
  const [dropDownStatus, setDropDownStatus] = useState(false);

  const capitalizeFirstLetter = (data: string) => {
    if (!data) {
      return '';
    }
    return data.charAt(0).toUpperCase() + data.slice(1).toLowerCase();
  };

  const get_name = () => {
    if (!firstName && !lastName) {
      return 'User';
    }
    if (!lastName) {
      return capitalizeFirstLetter(firstName);
    }
    return capitalizeFirstLetter(firstName) + ' ' + capitalizeFirstLetter(lastName);
  };

  const get_initials = () => {
    if (!firstName && !lastName) {
      return 'U';
    }
    const firstNameIn = firstName.charAt(0);
    if (!lastName) {
      return capitalizeFirstLetter(firstNameIn);
    }
    const lastNameIn = lastName.charAt(0);
    return capitalizeFirstLetter(firstNameIn) + capitalizeFirstLetter(lastNameIn);
  };

  const get_email = () => {
    return email || 'user@example.com';
  };

  const handleLogout = async () => {
    await logout();
  };

  const goToProfile = () => {
    setDropDownStatus(false);
    navigate('/lib-user-profile');
  };

  const toggleDropdown = () => {
    setDropDownStatus(!dropDownStatus);
  };

  return (
    <div>
      <button
        id="dropdownMenu"
        type="button"
        className={`flex gap-2.5 items-center p-1 ${
          dropDownStatus ? 'shadow-[0_20px_56px_-12px_rgba(0,0,0,0.25)]' : ''
        }`}
        onClick={toggleDropdown}
      >
        <div className="flex p-2">
          <div className="flex items-center gap-2">
            <div className="flex py-3 pr-2 pl-[9px] rounded-[20px] bg-frame-bg-300">
              <span className="font-medium text-base/[16px] text-color-font-600 font-sans">
                {get_initials()}
              </span>
            </div>
            <div className="flex flex-col items-start my-0.5">
              <div className="flex basis-full justify-start items-center">
                <span className="text-sm font-medium text-color-font-600 font-sans">
                  {get_name()}
                </span>
              </div>
              <div className="flex basis-full justify-start items-center">
                <span className="text-xs font-medium text-color-font-400 text-ellipsis overflow-hidden font-sans">
                  {get_email()}
                </span>
              </div>
            </div>
          </div>
        </div>
        <div className="p-1">
          <img src="assets/down-arrow.svg" alt="dropdown" />
        </div>
      </button>
      {dropDownStatus && (
        <div className="flex flex-col absolute w-[306.93px] rounded-b-md shadow-[0_20px_56px_-12px_rgba(0,0,0,0.25)] bg-frame-bg-100 overflow-visible z-50">
          <div className="flex px-4 py-2 items-center self-stretch border-b border-b-color-font-300">
            <button
              type="button"
              className="text-color-font-600 font-medium block text-sm font-sans"
              onClick={goToProfile}
            >
              Edit Profile
            </button>
          </div>
          <div className="flex px-4 py-2 items-center self-stretch">
            <button
              type="submit"
              className="text-color-font-600 font-medium block text-sm font-sans"
              onClick={handleLogout}
            >
              Logout
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

