import { createContext, useContext, useState, useCallback, type ReactNode } from 'react';
import type { HeaderConfig } from '../types';
import { DEFAULT_HEADER_CONFIG } from '../types';

interface HeaderConfigContextType {
  headerConfig: HeaderConfig;
  setHeaderConfig: (config: HeaderConfig) => void;
  resetHeader: () => void;
}

const HeaderConfigContext = createContext<HeaderConfigContextType | undefined>(undefined);

interface HeaderConfigProviderProps {
  children: ReactNode;
}

export const HeaderConfigProvider = ({ children }: HeaderConfigProviderProps) => {
  const [headerConfig, setHeaderConfigState] = useState<HeaderConfig>(DEFAULT_HEADER_CONFIG);

  const setHeaderConfig = useCallback((config: HeaderConfig) => {
    setHeaderConfigState((prevConfig) => {
      const mergedConfig = { ...DEFAULT_HEADER_CONFIG, ...prevConfig, ...config };
      return mergedConfig;
    });
  }, []);

  const resetHeader = useCallback(() => {
    setHeaderConfigState(DEFAULT_HEADER_CONFIG);
  }, []);

  const value: HeaderConfigContextType = {
    headerConfig,
    setHeaderConfig,
    resetHeader,
  };

  return <HeaderConfigContext.Provider value={value}>{children}</HeaderConfigContext.Provider>;
};

export const useHeaderConfig = () => {
  const context = useContext(HeaderConfigContext);
  if (context === undefined) {
    throw new Error('useHeaderConfig must be used within a HeaderConfigProvider');
  }
  return context;
};

